 14→
 15→const VisitedProfilePostCards = () =>{
 16→    const location = useLocation();
 17→    const userId = location.state?.userId || new URLSearchParams(location.search).get('userId');
 18→    const {user, session} = useAuth();
 19→
 20→    const navigate = useNavigate();
 21→
 22→    const {ref, inView} = useInView({
 23→        threshold: 0.2
 24→    })
 25→
 26→    const {data: journalData, isLoading: isLoadingJournals, isFetchingNextPage, fetchNextPage, hasNextPage,} = useInfiniteQuery({
 27→        queryKey: ['visitedProfileJournals', userId, user?.userData?.[0]?.id],
 28→        queryFn: ({pageParam = null, queryKey}) => getVisitedUserJournals(pageParam, 5, queryKey[1], queryKey[2]),
 29→        getNextPageParam: (lastPage) => {
 30→            if(lastPage.hasMore){
 31→                const lastJournal = lastPage?.data[lastPage?.data.length - 1]
 32→                return new Date(lastJournal.created_at).toISOString();
 33→            } else {
 34→                return undefined
 35→            }
 36→        },
 37→        enabled: !!userId,
 38→        refetchOnWindowFocus: false,
 39→        staleTime: 1000 * 60 * 5
 40→    })
 41→
 42→    const clickContent = handleCLickContent(navigate);
 43→    const mutateViews = useAddViewsMutation(session);
 44→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType = null, userReaction = null, reactionCount = 0) =>{
 45→        const formadata = new FormData();
 46→        formadata.append('journalId', journalId)
 47→        mutateViews.mutate(formadata);
 48→
 49→        clickContent(e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType, userReaction, reactionCount);
 50→    }
 51→
 52→    useEffect(() =>{
 53→        // console.log(userId)
 54→    },[userId])
 55→
 56→    const [viewMode, setViewMode] = useState('grid');
 57→
 58→    useEffect(() =>{
 59→        if(!isFetchingNextPage && hasNextPage && inView){
 60→            fetchNextPage();
 61→        }
 62→    }, [inView, fetchNextPage, isFetchingNextPage, hasNextPage])
 63→
 64→    const handleToggleView = useCallback(() => {
 65→        setViewMode((prev) => (prev === 'list' ? 'grid' : 'list'));
 66→    }, []);
 67→
 68→    const journals = journalData?.pages.flatMap((page) => page.data) || [];
 69→
 70→
 71→   if(isLoadingJournals){
 72→        return(
 73→            <>
 74→            <div className='profile-postcards-loading-container'>
