 15→    const navigate = useNavigate();
 16→    const {ref, inView} = useInView({threshold: 0, rootMargin: '200px'})
 17→
 18→    const {data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage} = useInfiniteQuery({
 19→        queryKey: ['getMyOpinions', session?.user?.id],
 20→        queryFn: ({pageParam = null}) => getMyOpinions(pageParam, 5, session?.access_token),
 21→        getNextPageParam: (lastPage) => {
 22→            if(lastPage.hasMore){
 23→                const lastOpinion = lastPage?.data[lastPage.data.length - 1];
 24→                return lastOpinion.id
 25→            } else {
 26→                return undefined;
 27→            }
 28→        },
 29→        refetchOnWindowFocus: false,
 30→        enabled: !!session,
 31→        staleTime: 1000 * 60 * 5
 32→    })
 33→
 34→    const handleClickContent = (e, opinionId, userId) =>{
 35→        e.stopPropagation();
 36→        if(!session) return openAuthModal();
 37→        navigate('/home/opinionsViewer', {
 38→            state: {
 39→                opinionId: opinionId,
 40→                userId: userId
 41→            }
 42→        })
 43→    }
 44→
 45→    useEffect(() =>{
 46→        if(inView && hasNextPage && !isFetchingNextPage){
 47→            fetchNextPage();
 48→        }
 49→    }, [inView, hasNextPage, isFetchingNextPage, fetchNextPage])
 50→
 51→    const opinions = data?.pages?.flatMap((page) => page.data) || [];
