 62→
 63→    return(
 64→        <>
 65→        <AnimatePresence>
 66→        <div className="my-opinions-container">
 67→
 68→            {opinions.map((opinion) => (
 69→                <motion.div
 70→                    className="ov-card"
 71→                    key={opinion.id}
 72→                    initial={{ opacity: 0, y: 12 }}
 73→                    animate={{ opacity: 1, y: 0 }}
 74→                    transition={{ duration: 0.3, ease: "easeOut" }}
 75→                >
 76→                    <div className="ov-user-row">
 77→                        <div className={`ov-avatar-container ${user?.userData[0]?.badge === 'legend' ? 'avatar-ring-legend' : user?.userData[0]?.badge === 'og' ? 'avatar-ring-og' : ''}`}>
 78→                            <img className="ov-avatar" src={user?.userData[0].image_url || "../../assets/profile.jpg"} alt={`${user?.userData?.[0]?.name || "User"} profile picture`} />
 79→                        </div>
 80→                        <span className="ov-username">{user?.userData[0].name}</span>
 81→                        <VerifiedBadge badge={user?.userData[0]?.badge} size={14} />
 82→                        <span className="ov-dot">·</span>
 83→                        <span className="ov-date">{formatPostDate(opinion.created_at)}</span>
 84→                    </div>
 85→
 86→                    <div
 87→                        onClick={(e) => handleClickContent(e, opinion.id, user?.userData[0].id)}
 88→                        className="ov-body"
 89→                    >
 90→                        {opinion.opinion}
 91→                    </div>
 92→
 93→                    <div className="ov-meta-bar">
 94→                        <span className="ov-reply-pill" onClick={(e) => { e.stopPropagation(); navigate('/home/opinionsViewer', { state: { opinionId: opinion.id, userId: opinion.user_id } }); }}>
 95→                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
 96→                                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
 97→                            </svg>
 98→                            {opinion.reply_count || 0} {opinion.reply_count === 1 ? 'reply' : 'replies'}
 99→                        </span>
100→                        <span className="ov-full-date">
101→                            {new Date(opinion.created_at).toLocaleDateString('en-US', {
102→                                month: 'long',
103→                                day: '2-digit',
104→                                year: 'numeric',
105→                            })}
106→                        </span>
107→                    </div>
108→                </motion.div>
109→            ))}
110→
111→            <div ref={ref} className="my-opinions-inview-container">
112→
113→            </div>
114→
115→        </div>
116→        </AnimatePresence>
117→        </>
118→    )
119→}
