142→    const handleConfirmDeleteJournal = async(e, journalId, token, image_url) =>{
143→        e.stopPropagation();
144→
145→        const imageUrlArray = [image_url];
146→        const queryKey = ['userJournals', user?.userData?.[0].id];
147→        let previousUserJournals = null;
148→        // console.log({
149→        //     journalId: journalId,
150→        //     image_url: imageUrlArray,
151→        //     token: token
152→        // })
153→
154→        try {
155→            setIsDeletingJournal(true);
156→            previousUserJournals = queryClient.getQueryData(queryKey);
157→
158→            queryClient.setQueryData(queryKey, (old) => {
159→                if (!old || !Array.isArray(old.pages)) return old;
160→
161→                return {
162→                    ...old,
163→                    pages: old.pages.map((page) => ({
164→                        ...page,
165→                        data: Array.isArray(page?.data)
166→                            ? page.data.filter((journal) => journal?.id !== journalId)
167→                            : page?.data
168→                    }))
169→                };
170→            });
171→
172→            const deleteJournalPromise = deleteJournal(journalId, token,)
173→            const deleteImageJournalPromise = image_url ? deleteJournalImage(token, imageUrlArray) : Promise.resolve(null);
174→
175→            const [deletePostJournal, deletePostJournalImage] = await Promise.allSettled([
176→                deleteJournalPromise,
177→                deleteImageJournalPromise,
178→            ])
179→            if(deletePostJournal || deletePostJournalImage){
180→                // console.log({deletePostJournal: deletePostJournal, deletePostJournalImage: deletePostJournalImage})
181→            }
182→
183→            if(deletePostJournal.status !== 'fulfilled'){
184→                queryClient.setQueryData(queryKey, previousUserJournals);
185→                throw deletePostJournal.reason || new Error('failed to delete journal');
186→            }
187→
188→            setJournalIsDeleted(true)
189→            // Only refetch the user's own journal list immediately.
190→            // Mark other feeds as stale — they'll refetch on next visit.
191→            queryClient.invalidateQueries({ queryKey: queryKey });
192→            queryClient.invalidateQueries({ queryKey: ['journals'], refetchType: 'none' });
193→            queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'], refetchType: 'none' });
194→
195→            setTimeout(() =>{
196→                setIsDeletingJournal(false)
197→                setJournalIsDeleted(false)
198→                setShowConfirmationBttn(null)
199→            }, 1500)
200→
201→        } catch (error) {
202→            if(previousUserJournals){
203→                queryClient.setQueryData(queryKey, previousUserJournals);
204→            }
205→            console.error("Error deleting journal:", error);
206→            setIsDeletingJournal(false);
207→        }
208→    }
