        setShowSettings(null);
        let content = journalContent;
        if (!content) {
            try {
                const result = await getJournalContent(journalId);
                content = result?.journal?.content;
            } catch (err) {
                console.error('failed to fetch journal for edit:', err);
                return;
            }
        }
        const data = {
            content,
            id: journalId,
            title: journalTitle
        }
        setJournalData(data);
        setShowEditor(showEditor === journalId ? null : journalId);
    }

    const handleClickCloseEditor = () => {
        setShowEditor(null)
    }

    const handleClickEditRepostCaption = (e, journalId, currentCaption) => {
        e.stopPropagation();
        setShowSettings(null);
        setCaptionData({id: journalId});
        setCaptionText(currentCaption || '');
        setShowCaptionEditor(journalId);
    }

    const handleSaveRepostCaption = async() => {
        if(!captionData?.id || isSavingCaption) return;
        try {
            setIsSavingCaption(true);
            await updateRepostCaption(session?.access_token, {
                journalId: captionData.id,
                caption: captionText
            });
            // Only refetch user's journals immediately; mark others stale.
            queryClient.invalidateQueries({queryKey: ['userJournals']});
            queryClient.invalidateQueries({queryKey: ['journals'], refetchType: 'none'});
            queryClient.invalidateQueries({queryKey: ['visitedProfileJournals'], refetchType: 'none'});
            setShowCaptionEditor(null);
            setCaptionData(null);
            setCaptionText('');
        } catch (error) {
            console.error('failed to update repost caption:', error);
        } finally {
            setIsSavingCaption(false);
