  1→import {useLocation, useNavigate } from 'react-router-dom';
  2→import './profilepostcards.css';
  3→import { useInfiniteQuery } from '@tanstack/react-query';
  4→import { useEffect, useState, useCallback } from 'react';
  5→import { MoonLoader } from 'react-spinners';
  6→import { motion } from 'framer-motion';
  7→import { useInView } from 'react-intersection-observer';
  8→import { handleCLickContent } from '../../../../../helpers/handleClicks';
  9→import { useAuth } from '../../../../Context/useAuth';
 10→import { getVisitedUserJournals } from '../../../../../API/Api';
 11→import { useAddViewsMutation } from '../../../../utils/useMutation';
 12→import VerifiedBadge from '../../../Badge/VerifiedBadge';
 13→import { handleImageFallback } from '../../../../utils/handleImageFallback';
 14→
 15→const VisitedProfilePostCards = () =>{
 16→    const location = useLocation();
 17→    const userId = location.state?.userId || new URLSearchParams(location.search).get('userId');
 18→    const {user, session} = useAuth();
 19→
 20→    const navigate = useNavigate();
 21→
 22→    const {ref, inView} = useInView({
 23→        threshold: 0.2
 24→    })
 25→
 26→    const {data: journalData, isLoading: isLoadingJournals, isFetchingNextPage, fetchNextPage, hasNextPage,} = useInfiniteQuery({
 27→        queryKey: ['visitedProfileJournals', userId, user?.userData?.[0]?.id],
 28→        queryFn: ({pageParam = null, queryKey}) => getVisitedUserJournals(pageParam, 5, queryKey[1], queryKey[2]),
 29→        getNextPageParam: (lastPage) => {
 30→            if(lastPage.hasMore){
 31→                const lastJournal = lastPage?.data[lastPage?.data.length - 1]
 32→                return new Date(lastJournal.created_at).toISOString();
 33→            } else {
 34→                return undefined
 35→            }
 36→        },
 37→        enabled: !!userId,
 38→        refetchOnWindowFocus: false,
 39→        staleTime: 1000 * 60 * 5
 40→    })
 41→
 42→    const clickContent = handleCLickContent(navigate);
 43→    const mutateViews = useAddViewsMutation(session);
 44→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType = null, userReaction = null, reactionCount = 0) =>{
 45→        const formadata = new FormData();
 46→        formadata.append('journalId', journalId)
 47→        mutateViews.mutate(formadata);
 48→
 49→        clickContent(e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType, userReaction, reactionCount);
 50→    }
 51→
 52→    useEffect(() =>{
 53→        // console.log(userId)
 54→    },[userId])
 55→
 56→    const [viewMode, setViewMode] = useState('grid');
 57→
 58→    useEffect(() =>{
 59→        if(!isFetchingNextPage && hasNextPage && inView){
 60→            fetchNextPage();
 61→        }
 62→    }, [inView, fetchNextPage, isFetchingNextPage, hasNextPage])
 63→
 64→    const handleToggleView = useCallback(() => {
 65→        setViewMode((prev) => (prev === 'list' ? 'grid' : 'list'));
 66→    }, []);
 67→
 68→    const journals = journalData?.pages.flatMap((page) => page.data) || [];
 69→
 70→
 71→   if(isLoadingJournals){
 72→        return(
 73→            <>
 74→            <div className='profile-postcards-loading-container'>
 75→                <MoonLoader loading={isLoadingJournals} color="var(--loader-color)" size={20} speedMultiplier={0.5}/>
 76→            </div>
 77→            </>
 78→        )
 79→    }
 80→    
 81→
 82→    if(journalData && !journals?.length > 0){
 83→        return (
 84→            <div className='profile-postcards-loading-container'>
 85→                No post available!
 86→            </div>
 87→        )
 88→    }
 89→
 90→    return(
 91→        <>
 92→        <div className='profile-postcards-parent-container'>
 93→            <div className="postcards-header-row">
 94→                <h2 className="postcards-heading">
 95→                    Posts <span className="postcards-count">({journals.length})</span>
 96→                </h2>
 97→                <div className="postcards-header-actions">
 98→                    <button
 99→                        className={`postcards-view-toggle-btn ${viewMode === 'grid' ? 'is-active' : ''}`}
100→                        onClick={handleToggleView}
101→                        title={viewMode === 'grid' ? 'Switch to list' : 'Switch to grid'}
102→                    >
103→                        {viewMode === 'grid' ? (
104→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-520v-320h320v320H120Zm0 400v-320h320v320H120Zm400-400v-320h320v320H520Zm0 400v-320h320v320H520Z"/></svg>
105→                        ) : (
106→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-200v-560h720v560H120Z"/></svg>
107→                        )}
108→                    </button>
109→                </div>
110→            </div>
111→
112→            {viewMode === 'grid' ? (
113→                <div className="postcards-grid-view">
114→                    {journals.map((journal) => {
115→                        const previewText = journal?.preview_text || '';
116→                        const thumbnail = journal?.thumbnail_url || null;
117→                        return (
118→                            <motion.div
119→                                key={journal.id}
120→                                className="postcards-grid-item"
121→                                initial={{ opacity: 0, scale: 0.95 }}
122→                                animate={{ opacity: 1, scale: 1 }}
123→                                transition={{ duration: 0.25, ease: 'easeOut' }}
124→                                onClick={(e) => viewContent(e, null, '', journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)}
125→                            >
126→                                {thumbnail ? (
127→                                    <div className="postcards-grid-img-wrap">
128→                                        <img className="postcards-grid-thumb" src={thumbnail} alt={journal?.title ? `${journal.title} cover image` : "Post cover image"} loading="lazy" onError={handleImageFallback} />
129→                                    </div>
130→                                ) : null}
131→                                <div className="postcards-grid-body">
132→                                    <h3 className="postcards-grid-title">{journal.title.length > 32 ? `${journal.title.substring(0, 32)}...` : journal.title}</h3>
133→                                    {previewText && (
134→                                        <p className="postcards-grid-snippet">{previewText.length > 50 ? `${previewText.substring(0, 50)}...` : previewText}</p>
135→                                    )}
136→                                </div>
137→                            </motion.div>
138→                        );
139→                    })}
140→                </div>
141→            ) : (
142→            <div className="postcards-list-view">
143→            {journals.map((journal, index) => {
144→                const previewText = journal?.preview_text || '';
145→                const thumbnail = journal?.thumbnail_url || null;
146→                const badgeClass = journal.users.badge === 'legend' ? 'avatar-ring-legend' : journal.users.badge === 'og' ? 'avatar-ring-og' : '';
147→
148→                return(
149→                    <motion.div
150→                        key={journal.id || index}
151→                        className="profile-postcards"
152→                        initial={{opacity: 0, y: 12}}
153→                        animate={{opacity: 1, y: 0}}
154→                        transition={{duration: 0.3, ease: 'easeOut'}}
155→                    >
156→                        {thumbnail && (
157→                            <img
158→                                className="card-image-banner"
159→                                src={thumbnail}
160→                                alt={journal?.title ? `${journal.title} cover image` : "Post cover image"}
161→                                loading="lazy"
162→                                onError={handleImageFallback}
163→                                onClick={(e) => viewContent(e, null, '', journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)}
164→                            />
165→                        )}
166→
167→                        <div className='user-profile-card-content'>
168→                            <div onClick={(e) => viewContent(e, null, '', journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)} className="content-container">
169→                                <div className='feed-text-content-container'>
170→                                    <div className='feed-title-content'>
171→                                        <h2 className="feed-title-profile-page">{journal.title.length > 55 ? `${journal.title.substring(0, 55)}...` : journal.title}</h2>
172→                                    </div>
173→                                    <p className="feed-text-content-profile-page">{previewText}</p>
174→                                </div>
175→                            </div>
176→
177→                            <div className="card-icons-container">
178→                                <div className='user-info-child-container'>
179→                                    <div className={`user-avatar-container ${badgeClass}`}>
180→                                        <img src={journal.users.image_url || '/assets/profile.jpg'} alt="user-profile" loading='lazy' className="user-info-avatar"/>
181→                                    </div>
182→                                    <div className="user-name-container">
183→                                        <p className="user-newsfeed-name-profile-page">{journal.users.name}</p>
184→                                        <VerifiedBadge badge={journal.users.badge} size={14} />
185→                                    </div>
186→                                    <div className="name-info-separator">•</div>
187→                                    <p className="user-post-date">{new Date(journal.created_at).toLocaleDateString('en-US', {
188→                                        month: 'long',
189→                                        day: 'numeric',
190→                                        year: 'numeric'
191→                                    })}</p>
192→
193→                                    <div className="user-post-settings">
194→                                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z"/></svg>
195→                                    </div>
196→                                </div>
197→                            </div>
198→                        </div>
199→                    </motion.div>
200→                )
201→            })}
202→            </div>
203→            )}
204→
205→            <div ref={ref} className='in-view-container'>
206→                {isFetchingNextPage && (
207→                    <MoonLoader size={20} color="var(--loader-color)" loading={isFetchingNextPage}/>
208→                )}
209→            </div>
210→
211→        </div>
212→        </>
213→    )
214→}
215→
216→export default VisitedProfilePostCards;
